#' JASP Enhanced Bayesian ANOVA
#'
#' jamovi-native shell for the JASP Bayesian ANOVA analysis.
#' @param data .
#' @param dependent .
#' @param fixedFactors .
#' @param covariates .
#' @param modelComparison .
#' @param posterior .
#' @param apaReport .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$status} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$about} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
enhancedBayesianAnova <- function(
    data,
    dependent,
    fixedFactors,
    covariates,
    modelComparison = TRUE,
    posterior = TRUE,
    apaReport = TRUE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("enhancedBayesianAnova requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dependent)) dependent <- jmvcore::resolveQuo(jmvcore::enquo(dependent))
    if ( ! missing(fixedFactors)) fixedFactors <- jmvcore::resolveQuo(jmvcore::enquo(fixedFactors))
    if ( ! missing(covariates)) covariates <- jmvcore::resolveQuo(jmvcore::enquo(covariates))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dependent), dependent, NULL),
            `if`( ! missing(fixedFactors), fixedFactors, NULL),
            `if`( ! missing(covariates), covariates, NULL))

    for (v in fixedFactors) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- enhancedBayesianAnovaOptions$new(
        dependent = dependent,
        fixedFactors = fixedFactors,
        covariates = covariates,
        modelComparison = modelComparison,
        posterior = posterior,
        apaReport = apaReport)

    analysis <- enhancedBayesianAnovaClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

